// htmx-lite: Minimal htmx-compatible engine (~3KB)
// Supports: hx-get, hx-post, hx-put, hx-delete, hx-trigger, hx-swap, hx-confirm, hx-target
(function(){
'use strict';
var htmx={version:'lite-1.0'};

function qsa(sel,root){return Array.prototype.slice.call((root||document).querySelectorAll(sel));}
function trigger(el,name,detail){el.dispatchEvent(new CustomEvent(name,{bubbles:true,detail:detail||{}}));}

function swap(target,content,mode){
  mode=mode||'innerHTML';
  if(mode==='innerHTML'){target.innerHTML=content;}
  else if(mode==='outerHTML'){target.outerHTML=content;}
  else if(mode==='beforeend'){target.insertAdjacentHTML('beforeend',content);}
  else if(mode==='afterbegin'){target.insertAdjacentHTML('afterbegin',content);}
  else if(mode==='none'){return;}
  trigger(target,'htmx:afterSwap',{});
  processElement(target);
}

function doRequest(el,method,url){
  var confirm=el.getAttribute('hx-confirm');
  if(confirm&&!window.confirm(confirm))return;

  var targetSel=el.getAttribute('hx-target');
  var target=targetSel?document.querySelector(targetSel):el;
  var swapMode=el.getAttribute('hx-swap')||'innerHTML';

  var pathInfo={requestPath:url};
  trigger(el,'htmx:beforeRequest',{pathInfo:pathInfo});

  var xhr=new XMLHttpRequest();
  xhr.open(method.toUpperCase(),url,true);
  xhr.setRequestHeader('HX-Request','true');
  xhr.onload=function(){
    if(xhr.status>=200&&xhr.status<300){
      if(swapMode!=='none'){swap(target,xhr.responseText,swapMode);}
      trigger(el,'htmx:afterRequest',{xhr:xhr,pathInfo:pathInfo,verb:method});
    } else {
      trigger(el,'htmx:responseError',{xhr:xhr,pathInfo:pathInfo});
    }
  };
  xhr.onerror=function(){trigger(el,'htmx:responseError',{xhr:xhr,pathInfo:pathInfo});};
  xhr.send();
}

function parseTrigger(spec){
  if(!spec)return null;
  var m=spec.match(/^every\s+(\d+)s$/);
  if(m)return{type:'poll',interval:parseInt(m[1],10)*1000};
  return{type:'event',event:spec};
}

var intervals=[];
function processElement(root){
  var methods=['get','post','put','delete'];
  methods.forEach(function(method){
    qsa('[hx-'+method+']',root).forEach(function(el){
      if(el._htmxBound)return;
      el._htmxBound=true;
      var url=el.getAttribute('hx-'+method);
      var trig=parseTrigger(el.getAttribute('hx-trigger'));

      if(trig&&trig.type==='poll'){
        var id=setInterval(function(){doRequest(el,method,url);},trig.interval);
        intervals.push(id);
      } else {
        var evt=(trig&&trig.event)||'click';
        if(el.tagName==='FORM')evt='submit';
        el.addEventListener(evt,function(e){
          e.preventDefault();
          doRequest(el,method,url);
        });
      }
    });
  });
}

// Process on load
if(document.readyState==='loading'){
  document.addEventListener('DOMContentLoaded',function(){processElement(document);});
} else {
  processElement(document);
}

// Re-process on dynamic content
var obs=new MutationObserver(function(muts){
  muts.forEach(function(m){
    m.addedNodes.forEach(function(n){
      if(n.nodeType===1)processElement(n);
    });
  });
});
obs.observe(document.body||document.documentElement,{childList:true,subtree:true});

htmx.trigger=trigger;
htmx.process=processElement;
window.htmx=htmx;
})();
